catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

    if (isLoading || newValue == '') {
        return;
    }

    switch (newValue) {

        case 'a3fb7b3c47ed8714e9a5d369316d43a1':
            g_form.setValue('priority', '3');
            break;

        case 'e7fb7b3c47ed8714e9a5d369316d43a2':
            g_form.setValue('priority', '1');
            break;

        case '2ffb7b3c47ed8714e9a5d369316d43a2':
            g_form.setValue('priority', '5');
            break;

        case '63fb7b3c47ed8714e9a5d369316d43a3':
            g_form.setValue('priority', '3');
            break;

        case 'a7fb7b3c47ed8714e9a5d369316d43a3':
            g_form.setValue('priority', '4');
            break;

        case 'ebfb7b3c47ed8714e9a5d369316d43a3':
            g_form.setValue('priority', '2');
            break;

        default:
            g_form.clearValue('priority');
    }
}
